import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"税务信息交换说明","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"compliance-and-tax/tax-information-exchange.md","filePath":"zh-CN/compliance-and-tax/tax-information-exchange.md"}'),l={name:"compliance-and-tax/tax-information-exchange.md"};function n(o,a,h,c,d,s){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="税务信息交换说明" tabindex="-1">税务信息交换说明 <a class="header-anchor" href="#税务信息交换说明" aria-label="Permalink to &quot;税务信息交换说明&quot;">​</a></h1><p>CRS 共同申报标准、客户税务信息申报要求及税务居住地判断方法。</p><h2 id="什么是-crs" tabindex="-1">什么是 CRS <a class="header-anchor" href="#什么是-crs" aria-label="Permalink to &quot;什么是 CRS&quot;">​</a></h2><p>CRS（Common Reporting Standard，共同申报标准）也称 AEOI（Automatic Exchange of Financial Account Information，金融账户信息自动交换标准），是经济合作与发展组织（OECD）为打击逃税和维护有效税制而制定的信息申报与交换规则。</p><p>所有参与国家/地区的金融机构必须遵守 CRS 要求收集资料，进行年度申报，与其他参与 CRS 国家/地区交换信息。香港是参与 CRS 的地区之一。</p><p><a href="https://www.oecd.org/en/topics/sub-issues/international-standards-on-tax-transparency/tax-transparency-resource-centre.html" target="_blank" rel="noreferrer">OECD 官网</a><br><a href="https://www.ird.gov.hk/chs/tax/dta_aeoi.htm" target="_blank" rel="noreferrer">香港税务局 AEOI 网站</a></p><h2 id="为何与我有关" tabindex="-1">为何与我有关 <a class="header-anchor" href="#为何与我有关" aria-label="Permalink to &quot;为何与我有关&quot;">​</a></h2><p>香港税务机关要求金融机构（包括长桥证券（香港））收集和报告客户税务状况相关的信息。</p><ul><li>开设账户或投资新金融产品时，需要填写并签署自我证明表格</li><li>税务身份或个人信息发生改变时，需及时通知更新税务资料</li></ul><h2 id="受影响的客户" tabindex="-1">受影响的客户 <a class="header-anchor" href="#受影响的客户" aria-label="Permalink to &quot;受影响的客户&quot;">​</a></h2><p>所有在长桥持有金融账户的客户均受 CRS 尽职审查程序约束，包括个人（直接或间接持有）、独资经营者及公司。</p><p>被辨认为须汇报的客户（即属税务管辖区的税务居民）将按 CRS 规定被申报。税务居留地仅为香港的客户无须被申报。</p><h2 id="税务居住地" tabindex="-1">税务居住地 <a class="header-anchor" href="#税务居住地" aria-label="Permalink to &quot;税务居住地&quot;">​</a></h2><p>一般根据以下因素判断：</p><ul><li>个人：身处之地或逗留时间（如一个课税年度超过 183 天）</li><li>公司：成为法团的地点或中央管理及控制的地点</li></ul><p>被要求缴交税款不代表自动成为该国税务居民。如有疑问请寻求专业税务或法律协助。</p><h2 id="需要提供的税务信息" tabindex="-1">需要提供的税务信息 <a class="header-anchor" href="#需要提供的税务信息" aria-label="Permalink to &quot;需要提供的税务信息&quot;">​</a></h2><ul><li>姓名、地址、出生日期</li><li>出生地（个人）/ 注册国家（公司）</li><li>税务居民国家</li><li>税务编号（TIN）或无税号原因</li><li>特定公司户的实控人信息（如适用）</li></ul><h2 id="被申报的信息" tabindex="-1">被申报的信息 <a class="header-anchor" href="#被申报的信息" aria-label="Permalink to &quot;被申报的信息&quot;">​</a></h2><ul><li>年末账户结余或总价值</li><li>年度内已记入账户的入款项（包括股息、利息、卖出金额等，不包括交易盈利）</li></ul><p>申报频率：一般一年一次。</p><h2 id="隐私保护" tabindex="-1">隐私保护 <a class="header-anchor" href="#隐私保护" aria-label="Permalink to &quot;隐私保护&quot;">​</a></h2><p>长桥严格遵守香港个人私隐条例和证监会信息安全要求，仅在法律规定下向相关税务机构申报客户信息。</p><p>作为金融机构，长桥不获允许提供税务或法律意见。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/compliance-and-tax/美股税表与股息税">美股税表与股息税</a> — 税务申报与预扣税率</li></ul>',26)])])}const m=e(l,[["render",n]]);export{u as __pageData,m as default};
